mapper.select:
SELECT o.customer_uuid AS customerUuid, MAX(o.customer_name) AS customerName, COUNT(*) AS totalRollCount, SUM(CASE WHEN dd.uuid IS NULL THEN 1 ELSE 0 END) AS availableRollCount, SUM(CASE WHEN dd.uuid IS NOT NULL THEN 1 ELSE 0 END) AS lockedRollCount, SUM(COALESCE(f.remaining_weight, f.actual_weight, 0)) AS totalWeight, SUM(CASE WHEN dd.uuid IS NULL THEN COALESCE(f.remaining_weight, f.actual_weight, 0) ELSE 0 END) AS availableWeight, SUM(CASE WHEN dd.uuid IS NOT NULL THEN COALESCE(f.remaining_weight, f.actual_weight, 0) ELSE 0 END) AS lockedWeight, SUM(CASE WHEN dd.uuid IS NOT NULL THEN dd.out_weight ELSE 0 END) AS plannedOutWeight, MIN(f.stock_in_time) AS oldestStockInTime, SUM(CASE WHEN f.stock_in_time IS NULL THEN 1 ELSE 0 END) AS stockInTimeUnknownCount, COUNT(DISTINCT f.warehouse_uuid) AS warehouseCount, GROUP_CONCAT(DISTINCT w.warehouse_name ORDER BY w.warehouse_name SEPARATOR '、') AS warehouseNames, GROUP_CONCAT(DISTINCT f.paper_name ORDER BY f.paper_name SEPARATOR '、') AS paperNames FROM biz_finish_roll f INNER JOIN biz_process_order o ON o.uuid = f.order_uuid
LEFT JOIN sys_warehouse w ON w.uuid = f.warehouse_uuid AND w.is_deleted = 0 WHERE
GROUP BY o.customer_uuid ORDER BY totalWeight DESC, customerName ASC LIMIT #{offset}, #{limit}

SELECT o.customer_uuid AS customerUuid, f.uuid AS finishUuid, f.finish_roll_no AS finishRollNo, CASE WHEN dd.uuid IS NULL THEN 1 ELSE 2 END AS stockState, d.uuid AS deliveryUuid, d.delivery_no AS deliveryNo FROM biz_finish_roll f INNER JOIN biz_process_order o ON o.uuid = f.order_uuid
LEFT JOIN biz_delivery_order d ON d.uuid = dd.delivery_uuid AND d.is_deleted = 0 WHERE AND o.customer_uuid = #{customerUuid} AND f.warehouse_uuid = #{warehouseUuid} AND f.uuid IN
#{finishUuid}
